Async/Await Types

TypeScript provides full type support for asynchronous operations with `async`/`await`.

### Async Function Return Types

An `async` function always returns a `Promise`:

```typescript
async function fetchData(): Promise<string> {
  return "data"; // Wrapped in Promise automatically
}

async function getNumber(): Promise<number> {
  return 42;
}

// Return type is inferred as Promise<string>
async function getMessage() {
  return "Hello";
}
```

### Awaiting Promises

```typescript
async function processData(): Promise<void> {
  const data = await fetchData(); // type: string
  console.log(data.toUpperCase());
}
```

### Promise Type Helpers

```typescript
type Unwrapped<T> = T extends Promise<infer U> ? U : T;

type PromiseString = Promise<string>;
type StringType = Unwrapped<PromiseString>; // string

// Built-in: Awaited<T>
type Str2 = Awaited<Promise<string>>; // string
```

### Error Handling

```typescript
async function safeFetch(url: string): Promise<{ data: unknown } | { error: string }> {
  try {
    const response = await fetch(url);
    const data = await response.json();
    return { data };
  } catch (err) {
    return { error: (err as Error).message };
  }
}

const result = await safeFetch("/api/data");
if ("error" in result) {
  console.error(result.error);
} else {
  console.log(result.data);
}
```

### Parallel Execution

```typescript
async function fetchMultiple(): Promise<[string, number, boolean]> {
  const [a, b, c] = await Promise.all([
    fetchString(),
    fetchNumber(),
    fetchBoolean()
  ]);
  return [a, b, c];
}
```

> **Key Point:** Always annotate async function return types as `Promise<T>` for clarity.

codeExample:
interface User {
  id: number;
  name: string;
  email: string;
}

// Typed async API call
async function getUser(id: number): Promise<User> {
  const response = await fetch(`/api/users/${id}`);

  if (!response.ok) {
    throw new Error(`Failed to fetch user: ${response.statusText}`);
  }

  return response.json() as Promise<User>;
}

// Using the async function
async function displayUser(id: number): Promise<void> {
  try {
    const user = await getUser(id);
    console.log(`${user.name} (${user.email})`);
  } catch (error) {
    console.error("Error:", error);
  }
}

// Awaited utility type
type UserPromise = ReturnType<typeof getUser>; // Promise<User>
type ResolvedUser = Awaited<UserPromise>; // User
